module top (
    input logic clk,
    input logic rst_n,
    input logic d,
    output logic q
);
always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        q <= 0;
    else
        q <= d;
end
endmodule

module top #(
    parameter DEPTH = 4
) (
    input logic [7:0] a [0:DEPTH-1],
    input logic [7:0] b [1:DEPTH],
    output logic y
);
logic [7:0] bank0 [0:DEPTH-1], bank1 [1:DEPTH];
endmodule

package state_pkg;
    typedef enum logic [1:0] {
        IDLE = 0,
        BUSY = 1
    } state_t;
endpackage

module top import state_pkg::state_t; (
    input state_t state,
    output logic y
);
endmodule

module child (
    input logic [7:0] a,
    output logic y
);
endmodule

module top #(
    parameter IDX = 1
) (
    output logic y
);
struct packed {
    logic [7:0] data;
    logic valid;
} cfgs [0:1];
child u_child (.a(cfgs[IDX].data), .y(y));
endmodule
